SET @admin_password_hash = '$2a$10$pVve8MtdwO0AadSEbiOMq.bOda8O2HqBNvE/r9pjBPrttkkVZK5Oq';

START TRANSACTION;

-- 1. Legacy permissions are no longer seeded.
