-- 2. Root menus

-- 3. Second-level menus under SYSTEM_ROOT

-- 3.1 Keep route metadata aligned for existing databases.
UPDATE sys_menu SET route_path = '/dashboard/console', component = 'dashboard/console', visible = 1, enabled = 1, updated_at = @seed_now WHERE code = 'DASHBOARD';
UPDATE sys_menu SET route_path = '/profile/index', component = 'profile/index', visible = 1, enabled = 1, updated_at = @seed_now WHERE code = 'PROFILE';
UPDATE sys_menu SET route_path = '/system/user', component = 'sys/user', visible = 1, enabled = 1, updated_at = @seed_now WHERE code = 'SYSTEM_ADMIN_USER';
UPDATE sys_menu SET route_path = '/system/member', component = 'sys/member', visible = 1, enabled = 1, updated_at = @seed_now WHERE code = 'SYSTEM_MEMBER_USER';
UPDATE sys_menu SET route_path = '/system/business-type', component = 'sys/business-type', visible = 1, enabled = 1, updated_at = @seed_now WHERE code = 'SYSTEM_BUSINESS_TYPE';
UPDATE sys_menu SET route_path = '/tenders', component = 'sys/tender', visible = 1, enabled = 1, updated_at = @seed_now WHERE code = 'SYSTEM_TENDER';
UPDATE sys_menu SET visible = 0, enabled = 0, updated_at = @seed_now WHERE code IN ('SYSTEM_USER', 'SYSTEM_AUDIT_RECORD', 'USER_AUDIT_BUTTON', 'USER_ROLE_BUTTON', 'SYSTEM_PERMISSION', 'PERMISSION_EDIT_BUTTON');
UPDATE sys_menu SET route_path = '/system/role', component = 'sys/role', visible = 1, enabled = 1, updated_at = @seed_now WHERE code = 'SYSTEM_ROLE';
UPDATE sys_menu SET route_path = '/system/permissions', component = 'sys/permissions', visible = 0, enabled = 0, updated_at = @seed_now WHERE code = 'SYSTEM_PERMISSION';
UPDATE sys_menu SET route_path = '/system/menu', component = 'sys/menu', visible = 1, enabled = 1, updated_at = @seed_now WHERE code = 'SYSTEM_MENU';
UPDATE sys_menu SET route_path = '/log', component = 'system/log', visible = 1, enabled = 1, updated_at = @seed_now WHERE code = 'SYSTEM_OPERATION_LOG';

-- 4. Button menus

UPDATE sys_menu
SET permission_code = NULL, updated_at = @seed_now
WHERE code IN (
    'DASHBOARD', 'PROFILE', 'SYSTEM_ROOT', 'SYSTEM_ADMIN_USER', 'SYSTEM_MEMBER_USER', 'SYSTEM_BUSINESS_TYPE',
    'SYSTEM_TENDER', 'SYSTEM_USER', 'SYSTEM_AUDIT_RECORD', 'SYSTEM_ROLE', 'SYSTEM_PERMISSION', 'SYSTEM_MENU',
    'SYSTEM_OPERATION_LOG', 'MEMBER_CREATE_BUTTON', 'MEMBER_EDIT_BUTTON', 'ADMIN_USER_CREATE_BUTTON',
    'ADMIN_USER_EDIT_BUTTON', 'ADMIN_USER_STATUS_BUTTON', 'ADMIN_USER_PASSWORD_BUTTON', 'ADMIN_USER_ROLE_BUTTON',
    'MEMBER_DOWNLOAD_BUTTON', 'MEMBER_STATUS_BUTTON', 'MEMBER_PASSWORD_BUTTON', 'BUSINESS_TYPE_CREATE_BUTTON',
    'BUSINESS_TYPE_EDIT_BUTTON', 'BUSINESS_TYPE_STATUS_BUTTON', 'BUSINESS_TYPE_DELETE_BUTTON', 'TENDER_CREATE_BUTTON',
    'TENDER_EDIT_BUTTON', 'TENDER_DELETE_BUTTON', 'TENDER_UPLOAD_BUTTON', 'USER_AUDIT_BUTTON', 'USER_ROLE_BUTTON',
    'ROLE_EDIT_BUTTON', 'PERMISSION_EDIT_BUTTON', 'MENU_EDIT_BUTTON', 'PROFILE_EDIT_BUTTON'
);
UPDATE sys_menu
SET visible = 0,
    enabled = 0,
    description = CONVERT(0xE69D83E99990E7AEA1E79086E5B7B2E5819CE794A8EFBC8CE68E88E69D83E4BBA5E88F9CE58D952FE68C89E992AEE7BC96E7A081E4B8BAE58786 USING utf8mb4),
    updated_at = @seed_now
WHERE code IN ('SYSTEM_PERMISSION', 'PERMISSION_EDIT_BUTTON');

-- 5. Roles

-- 6. Role bindings
UPDATE sys_role SET description = CONVERT(0xE68BA5E69C89E7B3BBE7BB9FE585A8E983A8E88F9CE58D952FE68C89E992AE USING utf8mb4), updated_at = @seed_now WHERE code = 'SUPER_ADMIN';
UPDATE sys_role SET description = CONVERT(0xE8B49FE8B4A3E4BC9AE59198E38081E68B9BE6A087E38081E8A792E889B2E38081E88F9CE58D95E5928CE697A5E5BF97E7AEA1E79086 USING utf8mb4), updated_at = @seed_now WHERE code = 'SYSTEM_ADMIN';
DELETE FROM sys_role_permission WHERE role_id IN (SELECT id FROM sys_role WHERE code IN ('SUPER_ADMIN', 'SYSTEM_ADMIN', 'USER_AUDITOR', 'NORMAL_USER'));
DELETE FROM sys_role_menu WHERE role_id IN (SELECT id FROM sys_role WHERE code IN ('SUPER_ADMIN', 'SYSTEM_ADMIN', 'USER_AUDITOR', 'NORMAL_USER'));
SELECT role.id, menu.id
FROM sys_role role
JOIN sys_menu menu ON role.code = 'SUPER_ADMIN' AND menu.enabled = 1;

